export const VIDEO_COLLECTION_SLUGS = Object.keys(VIDEO_COLLECTIONS);

/** Flat array of every video with its collection slug attached. */
export const ALL_VIDEOS: ReadonlyArray<VideoEntry & { collectionSlug: string; collectionName: string }> =
  Object.entries(VIDEO_COLLECTIONS).flatMap(([slug, coll]) =>
    coll.videos.map((v) => ({ ...v, collectionSlug: slug, collectionName: coll.name })),
  );
